afterSnippet:
String email = payload.get("email") == null ? "" : String.valueOf(payload.get("email")).trim();
// If an email is provided, it must contain '@'. If not provided (blank), it's accepted.
if (!email.isBlank() && !email.contains("@")) {
    throw new IllegalArgumentException("A valid email address is required if provided.");
}
